/**
 * packspec.ts — Netlify Function for PackSpec persistence
  *
   * GET  /.netlify/functions/packspec?skill_id=<uuid>
    *      Returns the learner's PackSpec for a given skill (or 404 if none yet).
     *
      * POST /.netlify/functions/packspec
       *      Body: { skill_id, event: WitnessEvent }
        *      Upserts the PackSpec, appends to witness_events, advances RC iteration,
         *      recomputes H_total + L_t_min, updates convergence status.
          *
           * Auth: Supabase JWT from Authorization: Bearer <token> header.
            */

            import { createClient } from '@supabase/supabase-js';
            import { corsHeaders } from './_shared/anthropic';

            // ── RCT constants ────────────────────────────────────────────────────────────
            const L_CLIFF = 0.62;         // Entropy Cliff threshold (§6.4)
            const TAU_R   = 0.75;         // Admission threshold
            const L_BASE  = 0.95;         // Max reliability for a probe-confirmed witness
            const H_INIT  = 42.0;         // Initial structural entropy (bits) — full uncertainty
            const DECAY_RATE = 0.015;     // Per-day reliability decay (m factor in L_t)

            // Location weights: probe channel (regimeReader) contributes most to H reduction
            const LOCATION_H_CONTRIBUTION: Record<string, number> = {
              depth: 4.8,
                breadth: 4.8,
                  channel: 5.2,
                    frame: 5.6,
                      implicature: 5.6,
                      };

                      // Verdict → posterior delta (how much a session event shifts admission confidence)
                      const VERDICT_DELTA: Record<string, number> = {
                        converged: +0.18,
                          shallow:   -0.04,
                            trap:      -0.12,
                              off:       -0.08,
                              };

                              interface WitnessEvent {
                                location: string;      // depth | breadth | channel | frame | implicature
                                  verdict: string;       // converged | shallow | trap | off
                                    regime_depth?: number; // R1..R5 slider position
                                      doc_name?: string;
                                      }

                                      // ── Supabase admin client (service role — bypasses RLS for server-side ops) ──
                                      function makeClient() {
                                        const url  = process.env.SUPABASE_URL;
                                          const key  = process.env.SUPABASE_SERVICE_ROLE_KEY;
                                            if (!url || !key) throw new Error('Supabase env vars not configured');
                                              return createClient(url, key, { auth: { persistSession: false } });
                                              }

                                              // ── JWT → user_id ─────────────────────────────────────────────────────────────
                                              async function getUserId(supabase: ReturnType<typeof createClient>, token: string): Promise<string> {
                                                const { data, error } = await supabase.auth.getUser(token);
                                                  if (error || !data.user) throw new Error('Unauthorized');
                                                    return data.user.id;
                                                    }

                                                    // ── L_t computation (§6.4) ───────────────────────────────────────────────────
                                                    function computeLt(R: number, daysSinceReinforcement: number): number {
                                                      const m = Math.max(0, 1 - DECAY_RATE * daysSinceReinforcement);
                                                        return 0.5 + R * m * (L_BASE - 0.5);
                                                        }

                                                        // ── H_total recompute from pack witnesses ────────────────────────────────────
                                                        function recomputeEntropy(pack: Record<string, unknown>): { H_total: number; L_t_min: number } {
                                                          const witnesses = (pack.witnesses as Array<Record<string, unknown>>) ?? [];
                                                            const now = Date.now();

                                                              let H_str = 0;
                                                                const resolvedLocations = new Set<string>();

                                                                  // Internal entropy: sum over admitted witnesses
                                                                    let H_int = 0;
                                                                      let L_t_min = 1.0;
                                                                        for (const w of witnesses) {
                                                                            if (w.admitted) {
                                                                                  const lastReinforced = w.last_reinforced as string ?? new Date().toISOString();
                                                                                        const daysSince = (now - new Date(lastReinforced).getTime()) / 86400000;
                                                                                              const R = (w.posterior as number) ?? 0.75;
                                                                                                    const Lt = computeLt(R, daysSince);
                                                                                                          w.L_t = Lt;
                                                                                                                if (Lt < L_t_min) L_t_min = Lt;
                                                                                                                      const ent = -Lt * Math.log2(Lt) - (1 - Lt) * Math.log2(1 - Lt);
                                                                                                                            H_int += Math.max(0, ent);
                                                                                                                                  resolvedLocations.add(w.location as string);
                                                                                                                                      }
                                                                                                                                        }
                                                                                                                                        
                                                                                                                                          // Structural entropy: unresolved locations
                                                                                                                                            const allLocations = ['depth', 'breadth', 'channel', 'frame', 'implicature'];
                                                                                                                                              for (const loc of allLocations) {
                                                                                                                                                  if (!resolvedLocations.has(loc)) {
                                                                                                                                                        H_str += LOCATION_H_CONTRIBUTION[loc] ?? 4.8;
                                                                                                                                                            }
                                                                                                                                                              }
                                                                                                                                                              
                                                                                                                                                                const H_total = Math.max(0, H_int + H_str);
                                                                                                                                                                  return { H_total, L_t_min: witnesses.length === 0 ? 0.5 : L_t_min };
                                                                                                                                                                  }
                                                                                                                                                                  
                                                                                                                                                                  // ── Status from H_total + L_t_min ────────────────────────────────────────────
                                                                                                                                                                  function computeStatus(H_total: number, L_t_min: number): 'converging' | 'certified' | 'decaying' {
                                                                                                                                                                    if (L_t_min < L_CLIFF) return 'decaying';
                                                                                                                                                                      if (H_total < 5.0 && L_t_min >= TAU_R) return 'certified';
                                                                                                                                                                        return 'converging';
                                                                                                                                                                        }
                                                                                                                                                                        
                                                                                                                                                                        // ── Handler ───────────────────────────────────────────────────────────────────
                                                                                                                                                                        export const handler = async (event: {
                                                                                                                                                                          httpMethod: string;
                                                                                                                                                                            headers: Record<string, string>;
                                                                                                                                                                              body: string | null;
                                                                                                                                                                                queryStringParameters: Record<string, string> | null;
                                                                                                                                                                                }) => {
                                                                                                                                                                                  if (event.httpMethod === 'OPTIONS') {
                                                                                                                                                                                      return { statusCode: 204, headers: corsHeaders, body: '' };
                                                                                                                                                                                        }
                                                                                                                                                                                        
                                                                                                                                                                                          const token = (event.headers['authorization'] ?? '').replace(/^Bearer\s+/i, '');
                                                                                                                                                                                            if (!token) {
                                                                                                                                                                                                return { statusCode: 401, headers: corsHeaders, body: JSON.stringify({ error: 'Missing auth token' }) };
                                                                                                                                                                                                  }
                                                                                                                                                                                                  
                                                                                                                                                                                                    try {
                                                                                                                                                                                                        const supabase = makeClient();
                                                                                                                                                                                                            const user_id = await getUserId(supabase, token);
                                                                                                                                                                                                            
                                                                                                                                                                                                                // ── GET: load PackSpec ────────────────────────────────────────────────────
                                                                                                                                                                                                                    if (event.httpMethod === 'GET') {
                                                                                                                                                                                                                          const skill_id = event.queryStringParameters?.skill_id;
                                                                                                                                                                                                                                if (!skill_id) {
                                                                                                                                                                                                                                        return { statusCode: 400, headers: corsHeaders, body: JSON.stringify({ error: 'skill_id required' }) };
                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                    const { data, error: err } = await supabase
                                                                                                                                                                                                                                                            .from('learner_packspecs')
                                                                                                                                                                                                                                                                    .select('*')
                                                                                                                                                                                                                                                                            .eq('user_id', user_id)
                                                                                                                                                                                                                                                                                    .eq('skill_id', skill_id)
                                                                                                                                                                                                                                                                                            .single();
                                                                                                                                                                                                                                                                                                  if (err && err.code === 'PGRST116') {
                                                                                                                                                                                                                                                                                                          return { statusCode: 404, headers: corsHeaders, body: JSON.stringify({ packspec: null }) };
                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                      if (err) throw err;
                                                                                                                                                                                                                                                                                                                            return { statusCode: 200, headers: corsHeaders, body: JSON.stringify({ packspec: data }) };
                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                    // ── POST: record witness event + update PackSpec ──────────────────────────
                                                                                                                                                                                                                                                                                                                                        if (event.httpMethod === 'POST') {
                                                                                                                                                                                                                                                                                                                                              const body = JSON.parse(event.body ?? '{}') as { skill_id: string; event: WitnessEvent };
                                                                                                                                                                                                                                                                                                                                                    const { skill_id, event: we } = body;
                                                                                                                                                                                                                                                                                                                                                          if (!skill_id || !we?.location || !we?.verdict) {
                                                                                                                                                                                                                                                                                                                                                                  return { statusCode: 400, headers: corsHeaders, body: JSON.stringify({ error: 'skill_id and event required' }) };
                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                              // Load or initialise PackSpec
                                                                                                                                                                                                                                                                                                                                                                                    const { data: existing } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                            .from('learner_packspecs')
                                                                                                                                                                                                                                                                                                                                                                                                    .select('*')
                                                                                                                                                                                                                                                                                                                                                                                                            .eq('user_id', user_id)
                                                                                                                                                                                                                                                                                                                                                                                                                    .eq('skill_id', skill_id)
                                                                                                                                                                                                                                                                                                                                                                                                                            .single();
                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                  const now = new Date().toISOString();
                                                                                                                                                                                                                                                                                                                                                                                                                                        let pack: Record<string, unknown> = (existing?.pack as Record<string, unknown>) ?? {
                                                                                                                                                                                                                                                                                                                                                                                                                                                schema_version: '0.1.0',
                                                                                                                                                                                                                                                                                                                                                                                                                                                        profile: 'apx.packspec.cus/0.1.0',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                pack: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          type: 'learner',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    skill_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              user_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        created: now,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        regimes: [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  { id: 'R_system',  kind: 'system',  description: 'The skill operational regime' },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            { id: 'R_learner', kind: 'learner', description: 'The learner cognitive regime' },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            witnesses: [],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cmust: { admitted_constraints: [], gap_witnesses: [], iteration: 0 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            entropy: { H_str: H_INIT, H_int: 0, H_total: H_INIT },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    convergence: { mode: 'weak', status: 'converging' },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Find or create witness for this location
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const witnesses = (pack.witnesses as Array<Record<string, unknown>>) ?? [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            let witness = witnesses.find((w) => w.location === we.location);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (!witness) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          witness = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    id: `W_${we.location.toUpperCase()}_${Date.now()}`,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              location: we.location,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        admitted: false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  posterior: 0.5,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            probe_count: 0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      probe_confirmed: false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                last_reinforced: now,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          L_t: 0.5,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    verdicts: [],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    witnesses.push(witness);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            pack.witnesses = witnesses;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Apply verdict delta to posterior
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const delta = VERDICT_DELTA[we.verdict] ?? 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const oldPost = (witness.posterior as number) ?? 0.5;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          witness.posterior = Math.min(0.98, Math.max(0.02, oldPost + delta));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                witness.probe_count = ((witness.probe_count as number) ?? 0) + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      witness.last_reinforced = now;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            (witness.verdicts as string[]).push(we.verdict);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // Admit if threshold crossed
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if ((witness.posterior as number) >= TAU_R && !witness.admitted) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                witness.admitted = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        witness.probe_confirmed = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                witness.admitted_at = now;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const cmust = pack.cmust as Record<string, unknown>;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const admitted = cmust.admitted_constraints as string[];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (!admitted.includes(we.location)) admitted.push(we.location);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const gap = cmust.gap_witnesses as string[];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const gapIdx = gap.indexOf(witness.id as string);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (gapIdx >= 0) gap.splice(gapIdx, 1);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } else if ((witness.posterior as number) < 0.5 && witness.admitted) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Demote if posterior drops significantly
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      witness.admitted = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              witness.probe_confirmed = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const cmust = pack.cmust as Record<string, unknown>;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const admitted = cmust.admitted_constraints as string[];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const idx = admitted.indexOf(we.location);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (idx >= 0) admitted.splice(idx, 1);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Advance iteration
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const cmust = pack.cmust as Record<string, unknown>;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      cmust.iteration = ((cmust.iteration as number) ?? 0) + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            pack.cmust = cmust;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // Recompute entropy + status
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const { H_total, L_t_min } = recomputeEntropy(pack);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              pack.entropy = { H_str: H_INIT - H_total, H_int: 0, H_total };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const status = computeStatus(H_total, L_t_min);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          (pack.convergence as Record<string, unknown>).status = status;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Upsert PackSpec
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const { data: upserted, error: upsertErr } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .from('learner_packspecs')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      .upsert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                user_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          skill_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    pack,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              iteration: cmust.iteration as number,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        H_total,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  L_t_min,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            status,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      last_probe_at: now,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                updated_at: now,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }, { onConflict: 'user_id,skill_id' })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .select('id')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .single();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (upsertErr) throw upsertErr;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const packspec_id = (upserted as { id: string }).id;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Append witness_event
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await supabase.from('witness_events').insert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        user_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                skill_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        packspec_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                location: we.location,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        verdict: we.verdict,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                regime_depth: we.regime_depth ?? null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        doc_name: we.doc_name ?? null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                admitted: witness.admitted as boolean,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        posterior: witness.posterior as number,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            statusCode: 200,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: corsHeaders,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            body: JSON.stringify({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      iteration: cmust.iteration,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                H_total,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          L_t_min,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    status,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              witness_admitted: witness.admitted,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        posterior: witness.posterior,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return { statusCode: 405, headers: corsHeaders, body: JSON.stringify({ error: 'Method not allowed' }) };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const msg = e instanceof Error ? e.message : 'PackSpec error';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const code = msg === 'Unauthorized' ? 401 : msg.includes('not configured') ? 503 : 500;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return { statusCode: code, headers: corsHeaders, body: JSON.stringify({ error: msg }) };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              };
